 T.MAX_INBPS , T.AVG_OUTBPS , T.MAX_OUTBPS FROM MDB_CP_IF_TRAFFIC_HH T INNER JOIN TB_EQUIP_MST FE ON T.EQUIP_ID = FE.EQUIP_ID INNER JOIN TB_IF_MST FI ON T.EQUIP_ID = FI.EQUIP_ID AND T.IF_NM = FI.IF_NM INNER JOIN TB_CP_LIST_MST CM ON CM.CP_ID = T.CP_ID
