MAX_OUTBPS, DAY28_AVG_INBPS, DAY28_AVG_OUTBPS, DAY28_MAX_INBPS, DAY28_MAX_OUTBPS, DAY29_AVG_INBPS, DAY29_AVG_OUTBPS, DAY29_MAX_INBPS, DAY29_MAX_OUTBPS, DAY30_AVG_INBPS, DAY30_AVG_OUTBPS, DAY30_MAX_INBPS, DAY30_MAX_OUTBPS, DAY31_AVG_INBPS, DAY31_AVG_OUTBPS, DAY31_MAX_INBPS, DAY31_MAX_OUTBPS FROM ( SELECT T.CP_ID , CM.CP_NM , CM.CP_TYPE_CD, T.COLLECT_Y4MMDD , T.PHYSICAL_SPEED , SUBSTR(T.COLLECT_Y4MMDD,-2) DD , T.AVG_INBPS , T.MAX_INBPS , T.AVG_OUTBPS , T.MAX_OUTBPS FROM MDB_CP_TRAFFIC_DD T INNER JOIN TB_CP_LIST_MST CM ON CM.CP_ID = T.CP_ID
