SELECT DOMAIN, COLLECT_Y4MMDD , WIRE_PHYSICAL_SPEED , WIRE_AVG_INBPS, WIRE_AVG_OUTBPS , WIRE_MAX_INBPS, WIRE_MAX_OUTBPS , WIRELESS_PHYSICAL_SPEED , WIRELESS_AVG_INBPS, WIRELESS_AVG_OUTBPS , WIRELESS_MAX_INBPS, WIRELESS_MAX_OUTBPS , IPTV_PHYSICAL_SPEED , IPTV_AVG_INBPS, IPTV_AVG_OUTBPS , IPTV_MAX_INBPS, IPTV_MAX_OUTBPS FROM ( SELECT T.SECTION_TYPE_CD , HH || '시' AS DOMAIN , T.COLLECT_Y4MMDD , T.PHYSICAL_SPEED , T.AVG_INBPS , T.MAX_INBPS , T.AVG_OUTBPS , T.MAX_OUTBPS FROM MDB_BACKBONE_TRAFFIC_HH T
AND T.SECTION_TYPE_CD = #{search_domain}
AND T.COLLECT_Y4MMDD = #{search_date}
) PIVOT ( MAX(PHYSICAL_SPEED) PHYSICAL_SPEED , AVG(AVG_INBPS) AVG_INBPS , AVG(AVG_OUTBPS) AVG_OUTBPS , MAX(MAX_INBPS) MAX_INBPS , MAX(MAX_OUTBPS) MAX_OUTBPS FOR SECTION_TYPE_CD IN ( -- select distinct SECTION_CD from TB_CP_SECTION_TYPE_CD AS ST) 'WIRE' AS WIRE, 'WIRELESS' AS WIRELESS, 'IPTV' AS IPTV ) ) ORDER BY DOMAIN

SELECT TO_CHAR(TO_DATE(COLLECT_Y4MMDD,'YYYYMMDD'), 'DD') || '일' AS DOMAIN , COLLECT_Y4MMDD , WIRE_PHYSICAL_SPEED , WIRE_AVG_INBPS, WIRE_AVG_OUTBPS , WIRE_MAX_INBPS, WIRE_MAX_OUTBPS , WIRELESS_PHYSICAL_SPEED , WIRELESS_AVG_INBPS, WIRELESS_AVG_OUTBPS , WIRELESS_MAX_INBPS, WIRELESS_MAX_OUTBPS , IPTV_PHYSICAL_SPEED , IPTV_AVG_INBPS, IPTV_AVG_OUTBPS , IPTV_MAX_INBPS, IPTV_MAX_OUTBPS FROM ( SELECT T.SECTION_TYPE_CD , T.COLLECT_Y4MMDD , T.PHYSICAL_SPEED , T.AVG_INBPS , T.MAX_INBPS , T.AVG_OUTBPS , T.MAX_OUTBPS FROM MDB_BACKBONE_TRAFFIC_DD T
AND T.SECTION_TYPE_CD = #{search_domain}
AND T.COLLECT_Y4MMDD LIKE #{search_date}||'__'
) PIVOT ( MAX(PHYSICAL_SPEED) PHYSICAL_SPEED , AVG(AVG_INBPS) AVG_INBPS , AVG(AVG_OUTBPS) AVG_OUTBPS , MAX(MAX_INBPS) MAX_INBPS , MAX(MAX_OUTBPS) MAX_OUTBPS FOR SECTION_TYPE_CD IN ( 'WIRE' AS WIRE, 'WIRELESS' AS WIRELESS, 'IPTV' AS IPTV ) ) ORDER BY DOMAIN

SELECT CP_ID, CP_NM, CP_TYPE_CD, DECODE(CP_TYPE_CD,'1','국내','2','해외','기타') CP_TYPE_NM , MNG_ORG_ID , MNG_USER_ID , MOBILE_PHONE_NUM, EMAIL , CONTENT , REG_TIME, REG_USER_ID , CHNG_TIME, CHNG_USER_ID FROM TB_CP_LIST_MST CM
AND CM.CP_TYPE_CD = #{search_cp_type}
AND CM.CP_NM = #{search_cp_nm}

SELECT DECODE(CP_TYPE_CD,'1','국내','2','해외','기타') CP_TYPE_CD , CM.CP_ID , CM.CP_NM , CM.MNG_USER_ID , ORG.TEAM_ORG_DESC , OFM.OFFICE_NM , FE.EQUIP_ID , FE.EQUIP_ALIAS , CCM.IF_NM , CCM.LL_NUM FROM TB_CP_LIST_MST CM INNER JOIN TB_CP_CIRCUIT_MST CCM ON CM.CP_ID =CCM.CP_ID --INNER JOIN TB_IF_MST FI ON FI.EQUIP_ID = CCM.EQUIP_ID AND FI.IF_NM = CCM.IF_NM INNER JOIN TB_EQUIP_MST FE ON FE.EQUIP_ID = CCM.EQUIP_ID INNER JOIN TB_OFFICE_ORG_MAPP_MST OMM ON FE.V_OFFICE_ID = OMM.OFFICE_ID AND FE.SVC_NET_CD=OMM.SVC_NET_CD INNER JOIN TB_OFFICE_MST OFM ON FE.V_OFFICE_ID = OFM.OFFICE_ID INNER JOIN ( SELECT O4.ORG_ID AS HEAD_ORG_ID, O4.ORG_NM AS HEAD_ORG_NM, O4.ORG_DESC AS HEAD_ORG_DESC , O5.ORG_ID AS NSC_ORG_ID, O5.ORG_NM AS NSC_ORG_NM, O5.ORG_DESC AS NSC_ORG_DESC , O6.ORG_ID AS TEAM_ORG_ID, O6.ORG_NM AS TEAM_ORG_NM, O6.ORG_DESC AS TEAM_ORG_DESC FROM MVW_EQUIP_ORG_MST O4 INNER JOIN MVW_EQUIP_ORG_MST O5 ON O4.ORG_ID = O5.HIGHER_ORG_ID INNER JOIN MVW_EQUIP_ORG_MST O6 ON O5.ORG_ID = O6.HIGHER_ORG_ID WHERE O4.HIGHER_ORG_ID ='000001' ) ORG ON OMM.ORG_ID =ORG.TEAM_ORG_ID
AND CM.CP_TYPE_CD = #{search_cp_type}
AND CM.CP_NM = #{search_input}
AND CCM.LL_NUM = #{search_input}
AND FE.EQUIP_ALIAS = #{search_input}
AND FE.MASTER_IP = #{search_input}

SELECT -- UF_CODE1('CLS_CD',ICM.CLS_CD ) CLS_NM ROWNUM , ICM.CLS_CD , (SELECT CD_NM FROM TB_CODE_CD WHERE CD = ICM.CLS_CD AND CATEGORY_CD='IDC_CLS_CD') CLS_NM , ICM.IDC_CENTER_NM , ICM.AS_NUM , ICM.LL_NUM , FE.EQUIP_ID , FE.EQUIP_ALIAS , FE.MASTER_IP , ICM.IF_NM FROM TB_IDC_CIRCUIT_MST ICM INNER JOIN TB_EQUIP_MST FE ON FE.EQUIP_ID = ICM.EQUIP_ID INNER JOIN TB_OFFICE_ORG_MAPP_MST OMM ON FE.V_OFFICE_ID = OMM.OFFICE_ID AND FE.SVC_NET_CD=OMM.SVC_NET_CD INNER JOIN TB_OFFICE_MST OFM ON FE.V_OFFICE_ID = OFM.OFFICE_ID INNER JOIN ( SELECT O4.ORG_ID AS HEAD_ORG_ID, O4.ORG_NM AS HEAD_ORG_NM, O4.ORG_DESC AS HEAD_ORG_DESC , O5.ORG_ID AS NSC_ORG_ID, O5.ORG_NM AS NSC_ORG_NM, O5.ORG_DESC AS NSC_ORG_DESC , O6.ORG_ID AS TEAM_ORG_ID, O6.ORG_NM AS TEAM_ORG_NM, O6.ORG_DESC AS TEAM_ORG_DESC FROM MVW_EQUIP_ORG_MST O4 INNER JOIN MVW_EQUIP_ORG_MST O5 ON O4.ORG_ID = O5.HIGHER_ORG_ID INNER JOIN MVW_EQUIP_ORG_MST O6 ON O5.ORG_ID = O6.HIGHER_ORG_ID WHERE O4.HIGHER_ORG_ID ='000001' ) ORG ON OMM.ORG_ID =ORG.TEAM_ORG_ID
AND ICM.CLS_CD = #{search_cls}
AND ICM.IDC_CENTER_NM = #{search_input}
AND ICM.AS_NUM = #{search_input}
AND ICM.LL_NUM = #{search_input}
AND FE.EQUIP_ALIAS = #{search_input}
AND FE.MASTER_IP = #{search_input}

SELECT ICM.CP_ID ,ICM.CP_NM ,ICM.CP_TYPE_CD, DECODE(ICM.CP_TYPE_CD, '1', '국내','2', '해외') AS CP_TYPE_NM ,ICM.MNG_ORG_ID ,ICM.MNG_USER_ID ,ICM.MOBILE_PHONE_NUM ,ICM.EMAIL ,ICM.CONTENT ,ICM.REG_TIME ,ICM.REG_USER_ID ,ICM.CHNG_TIME ,ICM.CHNG_USER_ID FROM TB_CP_LIST_MST ICM
AND ICM.CP_TYPE_CD = #{search_cp_type}
AND ICM.CP_NM '%' || #{search_cp_nm} || '%'

SELECT COUNT(CP_NM) AS CP_COUNT
FROM TB_CP_LIST_MST
WHERE CP_NM = #{CP_NM}

mapper.insert:
INSERT
INTO TB_CP_LIST_MST
(
    CP_TYPE_CD
    , CP_ID
    , CP_NM
    , MNG_ORG_ID
    , MNG_USER_ID
    , MOBILE_PHONE_NUM
    , EMAIL
    , CONTENT
    , REG_TIME
    , REG_USER_ID
)
VALUES (
    #{CP_TYPE_CD}
    , SQ_CP_LIST_MST.NEXTVAL
    , #{CP_NM}
    , #{MNG_ORG_ID}
    , #{MNG_USER_ID}
    , #{MOBILE_PHONE_NUM}
    , #{EMAIL}
    , #{CONTENT}
    , SYSDATE
    , #{USER_ID}
)

UPDATE TB_CP_LIST_MST

       CP_TYPE_CD = #{CP_TYPE_CD}
       , CP_NM = #{CP_NM}
       , MNG_ORG_ID = #{MNG_ORG_ID}
       , MNG_USER_ID = #{MNG_USER_ID}
       , MOBILE_PHONE_NUM = #{MOBILE_PHONE_NUM}
       , EMAIL = #{EMAIL}
       , CONTENT = #{CONTENT}
       , CHNG_TIME = SYSDATE
       , CHNG_USER_ID = #{USER_ID}

   WHERE CP_ID = #{CP_ID}

INSERT
INTO TB_CP_CIRCUIT_MST
(
    CP_ID
    , EQUIP_ID
    , IF_NM
    , LL_NUM
    , REG_TIME
    , REG_USER_ID
)
VALUES (
    #{CP_ID}
    , #{EQUIP_ID}
    , #{IF_NM}
    , #{LL_NUM}
    , SYSDATE
    , #{USER_ID}
)

UPDATE TB_CP_CIRCUIT_MST

    EQUIP_ID = #{EQUIP_ID}
    , IF_NM = #{IF_NM}
    , LL_NUM = #{LL_NUM}
    , CHNG_TIME = SYSDATE
    , CHNG_USER_ID = #{USER_ID}

WHERE CP_ID = #{CP_ID}

MERGE INTO TB_IDC_CIRCUIT_MST
USING DUAL ON (EQUIP_ID = #{EQUIP_ID} AND IF_NM = #{IF_NM})
WHEN MATCHED THEN 
    UPDATE SET 
         CLS_CD = #{CLS_NM}
        , IDC_CENTER_NM = #{IDC_CENTER_NM}
        , AS_NUM = #{AS_NUM}
        , LL_NUM = #{LL_NUM}
        , CHNG_TIME = SYSDATE
        , CHNG_USER_ID = #{USER_ID}
WHEN NOT MATCHED THEN 
    INSERT 
    (
        CLS_CD
        , EQUIP_ID
        , IF_NM
        , IDC_CENTER_NM
        , AS_NUM
        , LL_NUM
        , REG_TIME
        , REG_USER_ID
    )
